// ============================================
const CLIENT_NAME = 'Codesec Technologies';
const CLIENT_ADDRESS = 'Chennai, Tamil Nadu, India';
const REPORT_EMAIL = 'naveen@codesecure.in';
const MANAGER_NAME = 'ip-192-168-133-24';
const OPENSEARCH_URL = 'https://172.17.0.1:9200';
const OPENSEARCH_AUTH = 'Basic YWRtaW46bXBwN05ITk9tU3k4Y0FjMmlBcCpBaGdVYUU3aytsVEI=';
const CLIENT_LOGO = 'https://codesecure.in/images/codesec-logo1.png';
// ============================================

return [{
  json: {
    client_name: CLIENT_NAME,
    client_address: CLIENT_ADDRESS,
    report_email: REPORT_EMAIL,
    manager_name: MANAGER_NAME,
    opensearch_url: OPENSEARCH_URL,
    opensearch_auth: OPENSEARCH_AUTH,
    client_logo: CLIENT_LOGO
  }
}];

const config = $('Client Config').first().json;
const data = $input.first().json;
const aggs = data.aggregations.this_week;
const totalHits = aggs.doc_count;
const prevWeekTotal = data.aggregations.prev_week_total.doc_count;
const prevWeekLevels = (data.aggregations.prev_week_by_level.levels||{buckets:[]}).buckets;

const now = new Date();
const istOpt = { timeZone: 'Asia/Kolkata' };
const istDate = now.toLocaleDateString('en-IN', { ...istOpt, day:'2-digit', month:'2-digit', year:'numeric' });
const istTime = now.toLocaleTimeString('en-IN', { ...istOpt, hour12:true, hour:'2-digit', minute:'2-digit' });
const lastWeek = new Date(now - 604800000);
const fromDate = lastWeek.toLocaleDateString('en-IN', { ...istOpt, day:'2-digit', month:'short', year:'numeric' }) + ' ' + lastWeek.toLocaleTimeString('en-IN', { ...istOpt, hour:'2-digit', minute:'2-digit', hour12:true });
const toDate = now.toLocaleDateString('en-IN', { ...istOpt, day:'2-digit', month:'short', year:'numeric' }) + ' ' + now.toLocaleTimeString('en-IN', { ...istOpt, hour:'2-digit', minute:'2-digit', hour12:true });

// WAZUH OFFICIAL severity mapping
// Critical: level >= 15 | High: 12-14 | Medium: 7-11 | Low: 0-6
const levelBuckets = aggs.alerts_by_level.buckets;
const severityCounts = { Critical:0, High:0, Medium:0, Low:0 };
levelBuckets.forEach(b => {
  const lvl = b.key;
  if (lvl >= 15) severityCounts.Critical += b.doc_count;
  else if (lvl >= 12) severityCounts.High += b.doc_count;
  else if (lvl >= 7) severityCounts.Medium += b.doc_count;
  else severityCounts.Low += b.doc_count;
});

const topRules = aggs.top_rules.buckets.map(b => ({
  rule_id: b.key,
  description: b.rule_desc.buckets[0]?.key || 'N/A',
  level: b.rule_level.buckets[0]?.key || 0,
  count: b.doc_count
})).sort((a,b) => b.level-a.level || b.count-a.count);

const topAgents = aggs.top_agents.buckets.map(b => {
  const levels = (b.by_level||{buckets:[]}).buckets;
  let crit=0,high=0,med=0,low=0;
  levels.forEach(l=>{ if(l.key>=15)crit+=l.doc_count; else if(l.key>=12)high+=l.doc_count; else if(l.key>=7)med+=l.doc_count; else low+=l.doc_count; });
  return { name:b.key, count:b.doc_count, critical:crit, high:high, medium:med, low:low };
});
const mitreTechniques = aggs.mitre_techniques.buckets.map(b => ({ technique:b.key, count:b.doc_count }));
const mitreTactics = aggs.mitre_tactics.buckets.map(b => ({ tactic:b.key, count:b.doc_count }));
const timeline = aggs.alerts_over_time.buckets.map(b => ({
  hour: new Date(b.key_as_string).toLocaleTimeString('en-IN', { timeZone:'Asia/Kolkata', hour:'2-digit', minute:'2-digit', hour12:false }),
  count: b.doc_count
}));

return [{ json: {
  client_name: config.client_name, client_address: config.client_address,
  report_email: config.report_email, manager_name: config.manager_name,
  client_logo: config.client_logo, total_alerts: totalHits,
  severity_counts: severityCounts, top_rules: topRules,
  top_agents: topAgents, mitre_techniques: mitreTechniques,
  mitre_tactics: mitreTactics, timeline: timeline,
  auth_fail_count: aggs.auth_fail.doc_count,
  auth_fail_users: [...(aggs.auth_fail.by_win_user||{buckets:[]}).buckets.map(b=>({user:b.key,count:b.doc_count})),...(aggs.auth_fail.by_dstuser||{buckets:[]}).buckets.filter(b=>b.key!=='-'&&b.key!=='').map(b=>({user:b.key,count:b.doc_count})),...(aggs.auth_fail.by_srcuser||{buckets:[]}).buckets.filter(b=>b.key!=='-'&&b.key!=='').map(b=>({user:b.key,count:b.doc_count}))].reduce((acc,x)=>{const e=acc.find(a=>a.user===x.user);if(e)e.count=Math.max(e.count,x.count);else acc.push(x);return acc;},[]).sort((a,b)=>b.count-a.count).slice(0,5),
  auth_fail_ips: [...(aggs.auth_fail.by_win_ip||{buckets:[]}).buckets.map(b=>({ip:b.key,count:b.doc_count})),...(aggs.auth_fail.by_srcip||{buckets:[]}).buckets.filter(b=>b.key!=='-'&&b.key!=='').map(b=>({ip:b.key,count:b.doc_count}))].reduce((acc,x)=>{const e=acc.find(a=>a.ip===x.ip);if(e)e.count=Math.max(e.count,x.count);else acc.push(x);return acc;},[]).sort((a,b)=>b.count-a.count).slice(0,5),
  auth_fail_events: (aggs.auth_fail.top_rules||{buckets:[]}).buckets.map(b=>({desc:b.key,count:b.doc_count})),
  auth_success_count: aggs.auth_success.doc_count,
  auth_success_users: [...(aggs.auth_success.by_win_user||{buckets:[]}).buckets.map(b=>({user:b.key,count:b.doc_count})),...(aggs.auth_success.by_dstuser||{buckets:[]}).buckets.filter(b=>b.key!=='-'&&b.key!=='').map(b=>({user:b.key,count:b.doc_count})),...(aggs.auth_success.by_srcuser||{buckets:[]}).buckets.filter(b=>b.key!=='-'&&b.key!=='').map(b=>({user:b.key,count:b.doc_count}))].reduce((acc,x)=>{const e=acc.find(a=>a.user===x.user);if(e)e.count=Math.max(e.count,x.count);else acc.push(x);return acc;},[]).sort((a,b)=>b.count-a.count).slice(0,5),
  auth_success_events: (aggs.auth_success.top_rules||{buckets:[]}).buckets.map(b=>({desc:b.key,count:b.doc_count})),
  vuln_total: aggs.vuln.doc_count,
  vuln_by_sev: (aggs.vuln.by_sev||{buckets:[]}).buckets.map(b=>({severity:b.key,count:b.doc_count})),
  vuln_top_cve: (aggs.vuln.top_cve||{buckets:[]}).buckets.map(b=>({cve:b.key,count:b.doc_count})),
  vuln_top_agent: (aggs.vuln.top_agent||{buckets:[]}).buckets.map(b=>({agent:b.key,count:b.doc_count})),
  vuln_top_pkg: (aggs.vuln.top_pkg||{buckets:[]}).buckets.map(b=>({pkg:b.key,count:b.doc_count})),
  level12_count: aggs.level12.doc_count,
  sca_total: aggs.sca.doc_count,
  sca_results: (aggs.sca.by_result||{buckets:[]}).buckets.map(b=>({result:b.key,count:b.doc_count})),
  sca_policies: (aggs.sca.by_policy||{buckets:[]}).buckets.map(b=>({policy:b.key,count:b.doc_count})),
  fim_total: aggs.fim.doc_count,
  fim_events: (aggs.fim.by_event||{buckets:[]}).buckets.map(b=>({event:b.key,count:b.doc_count})),
  fim_agents: (aggs.fim.by_agent||{buckets:[]}).buckets.map(b=>({agent:b.key,count:b.doc_count})),
  fim_paths: (aggs.fim.by_path||{buckets:[]}).buckets.map(b=>({path:b.key,count:b.doc_count})),
    // Compliance mapping
    compliance_pci_total: aggs.compliance_pci.doc_count,
    compliance_pci_controls: (aggs.compliance_pci.controls||{buckets:[]}).buckets.map(b=>({control:b.key,count:b.doc_count})),
    compliance_hipaa_total: aggs.compliance_hipaa.doc_count,
    compliance_hipaa_controls: (aggs.compliance_hipaa.controls||{buckets:[]}).buckets.map(b=>({control:b.key,count:b.doc_count})),
    compliance_gdpr_total: aggs.compliance_gdpr.doc_count,
    compliance_gdpr_controls: (aggs.compliance_gdpr.controls||{buckets:[]}).buckets.map(b=>({control:b.key,count:b.doc_count})),
    compliance_nist_total: aggs.compliance_nist.doc_count,
    compliance_nist_controls: (aggs.compliance_nist.controls||{buckets:[]}).buckets.map(b=>({control:b.key,count:b.doc_count})),
    compliance_tsc_total: aggs.compliance_tsc.doc_count,
    compliance_tsc_controls: (aggs.compliance_tsc.controls||{buckets:[]}).buckets.map(b=>({control:b.key,count:b.doc_count})),
    // Top source IPs (merge windows + linux)
    top_srcips: (()=>{const m=new Map();(aggs.top_srcip||{buckets:[]}).buckets.forEach(b=>m.set(b.key,(m.get(b.key)||0)+b.doc_count));(aggs.top_srcip_linux||{buckets:[]}).buckets.forEach(b=>m.set(b.key,(m.get(b.key)||0)+b.doc_count));return Array.from(m.entries()).map(([ip,count])=>({ip,count})).sort((a,b)=>b.count-a.count).filter(x=>x.ip!=='127.0.0.1'&&!x.ip.startsWith('::1')).slice(0,10)})(),
    // Incident alerts (level 12+)
    incidents: ((aggs.incidents.by_rule||{buckets:[]}).buckets.map(b=>{const h=b.latest.hits.hits[0]._source;return {level:Math.round(b.max_level.value),description:(b.rule_desc.buckets[0]||{key:h.rule.description}).key,rule_id:b.key,count:b.doc_count,agents:b.agents.buckets.map(a=>a.key).join(', '),srcip:h.data?(h.data.srcip||((h.data.win||{}).eventdata||{}).ipAddress||'N/A'):'N/A',last_seen:new Date(h.timestamp).toLocaleString('en-IN',{timeZone:'Asia/Kolkata',hour12:false})}})),
    incident_count: aggs.incidents.doc_count,
    // Weekly daily trend data
    daily_trend: (aggs.alerts_over_time||{buckets:[]}).buckets.map(b=>({day:b.key_as_string,total:b.doc_count,low:(b.by_level.buckets.find(x=>x.key==='low')||{doc_count:0}).doc_count,medium:(b.by_level.buckets.find(x=>x.key==='medium')||{doc_count:0}).doc_count,high:(b.by_level.buckets.find(x=>x.key==='high')||{doc_count:0}).doc_count,critical:(b.by_level.buckets.find(x=>x.key==='critical')||{doc_count:0}).doc_count})),
    auth_fail_daily: (aggs.auth_fail_daily||{buckets:[]}).buckets.map(b=>({day:b.key_as_string,count:b.count.doc_count})),
    fim_daily: (aggs.fim_daily||{buckets:[]}).buckets.map(b=>({day:b.key_as_string,count:b.count.doc_count})),
    peak_day: (()=>{const b=(aggs.alerts_over_time||{buckets:[]}).buckets;if(!b.length)return 'N/A';const max=b.reduce((a,c)=>c.doc_count>a.doc_count?c:a,b[0]);return max.key_as_string+' ('+max.doc_count.toLocaleString()+' alerts)';})(),
  prev_week_total: prevWeekTotal,
  prev_week_severity: (()=>{ const s={Critical:0,High:0,Medium:0,Low:0}; prevWeekLevels.forEach(b=>{ if(b.key>=15)s.Critical+=b.doc_count; else if(b.key>=12)s.High+=b.doc_count; else if(b.key>=7)s.Medium+=b.doc_count; else s.Low+=b.doc_count; }); return s; })(),
  recommendations: (()=>{
    const recs = [];
    if(severityCounts.Critical>0) recs.push({icon:'!!',color:'#BD271E',text:''+severityCounts.Critical+' critical alerts detected. Investigate immediately and validate if these are true positives.'});
    if(severityCounts.High>50) recs.push({icon:'!',color:'#E7664C',text:'High volume of high-severity alerts ('+severityCounts.High.toLocaleString()+'). Review alert rules and tune false positives.'});
    const authFail = aggs.auth_fail.doc_count;
    if(authFail>100) recs.push({icon:'X',color:'#e74c3c',text:''+authFail.toLocaleString()+' authentication failures detected. Review failed login sources and consider IP blocking or account lockout policies.'});
    const vulnTotal = aggs.vuln.doc_count;
    if(vulnTotal>0) recs.push({icon:'V',color:'#e67e22',text:''+vulnTotal.toLocaleString()+' vulnerability alerts. Prioritize patching critical and high severity CVEs on affected agents.'});
    const scaFailed = ((aggs.sca.by_result||{buckets:[]}).buckets.find(b=>b.key==='failed')||{doc_count:0}).doc_count;
    if(scaFailed>0) recs.push({icon:'C',color:'#9b59b6',text:''+scaFailed+' SCA compliance checks failed. Review and remediate to improve security posture.'});
    if(topAgents.length>0 && topAgents[0].count > totalHits*0.3) recs.push({icon:'A',color:'#3498db',text:'Agent '+topAgents[0].name+' generates '+((topAgents[0].count/totalHits)*100).toFixed(0)+'% of all alerts. Investigate if misconfigured or under attack.'});
    if(recs.length===0) recs.push({icon:'OK',color:'#2ecc71',text:'No critical recommendations. Continue monitoring and maintain current security posture.'});
    return recs;
  })(),
  agent_risk: topAgents.map(a=>{
    const total = a.count||1;
    const critPct = (a.critical/total)*100;
    const highPct = (a.high/total)*100;
    const medPct = (a.medium/total)*100;
    const score = Math.min(100, Math.round(critPct*4 + highPct*2 + medPct*0.3));
    let risk,note;
    if(a.critical>0){risk='Critical';note=a.critical+' critical alerts - investigate immediately';}
    else if(a.high>10){risk='High';note=a.high+' high severity alerts - review required';}
    else if(score>=30){risk='Medium';note='Elevated alert volume - monitor closely';}
    else {risk='Low';note='Normal activity - routine monitoring';}
    return { name:a.name, count:a.count, critical:a.critical, high:a.high, medium:a.medium, low:a.low, score:score, risk:risk, note:note };
  }).sort((a,b)=>b.score-a.score),
  from_date: fromDate, to_date: toDate, ist_date: istDate, ist_time: istTime
}}];

const d = $input.first().json;
const sc = d.severity_counts;

// Wazuh official severity colors
const sevDef = [
  { key:'Critical', color:'#BD271E', range:'Level 15+' },
  { key:'High', color:'#E7664C', range:'Level 12-14' },
  { key:'Medium', color:'#D6BF57', range:'Level 7-11' },
  { key:'Low', color:'#6DCCB1', range:'Level 0-6' }
];

// SVG Donut
function svgDonut(data, w, h, r, r2) {
  const cx=w/2, cy=h/2;
  const total = data.reduce((s,x)=>s+x.value,0)||1;
  let cum=-90; const paths=data.filter(x=>x.value>0).map(x=>{
    const pct=x.value/total, ang=pct*360;
    const s=cum*Math.PI/180, e=(cum+ang)*Math.PI/180; cum+=ang;
    const la=ang>180?1:0;
    const x1=cx+r*Math.cos(s),y1=cy+r*Math.sin(s);
    const x2=cx+r*Math.cos(e),y2=cy+r*Math.sin(e);
    const x3=cx+r2*Math.cos(e),y3=cy+r2*Math.sin(e);
    const x4=cx+r2*Math.cos(s),y4=cy+r2*Math.sin(s);
    return `<path d="M${x1},${y1} A${r},${r} 0 ${la},1 ${x2},${y2} L${x3},${y3} A${r2},${r2} 0 ${la},0 ${x4},${y4}Z" fill="${x.color}"/>`;
  }).join('');
  return `<svg width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">${paths}<text x="${cx}" y="${cy-6}" text-anchor="middle" font-size="18" font-weight="800" fill="#2c3e50">${total.toLocaleString()}</text><text x="${cx}" y="${cy+10}" text-anchor="middle" font-size="9" fill="#95a5a6">Total Alerts</text></svg>`;
}

// SVG Vertical bars
function svgVBars(items, w, h) {
  const pad={t:15,b:40,l:5,r:5};
  const cW=w-pad.l-pad.r, cH=h-pad.t-pad.b;
  const max=Math.max(...items.map(i=>i.value),1);
  const bW=Math.min(Math.floor(cW/items.length)-2,22);
  const gap=(cW-bW*items.length)/(items.length+1);
  let s='';
  items.forEach((it,i)=>{
    const bH=Math.max((it.value/max)*cH,2);
    const x=pad.l+gap+(bW+gap)*i, y=pad.t+cH-bH;
    s+=`<rect x="${x}" y="${y}" width="${bW}" height="${bH}" fill="${it.color||'#3498db'}" rx="2"/>`;
    s+=`<text x="${x+bW/2}" y="${pad.t+cH+12}" text-anchor="middle" font-size="5.5" fill="#7f8c8d" transform="rotate(50,${x+bW/2},${pad.t+cH+12})">${it.label}</text>`;
    s+=`<text x="${x+bW/2}" y="${y-4}" text-anchor="middle" font-size="5.5" fill="#555">${it.value>=1000000?(it.value/1000000).toFixed(1)+'M':it.value>=1000?(it.value/1000).toFixed(0)+'k':it.value}</text>`;
  });
  s+=`<line x1="${pad.l}" y1="${pad.t+cH}" x2="${w-pad.r}" y2="${pad.t+cH}" stroke="#ecf0f1" stroke-width="1"/>`;
  return `<svg width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">${s}</svg>`;
}

// SVG Horizontal bars
function svgHBars(items, w, h) {
  const pad={t:5,b:5,l:110,r:55};
  const cW=w-pad.l-pad.r;
  const bH=Math.min(Math.floor((h-pad.t-pad.b)/items.length)-3,16);
  const max=Math.max(...items.map(i=>i.value),1);
  let s='';
  items.forEach((it,i)=>{
    const bw=Math.max((it.value/max)*cW,3);
    const y=pad.t+(bH+3)*i;
    s+=`<text x="${pad.l-5}" y="${y+bH/2+3}" text-anchor="end" font-size="7" fill="#2c3e50">${it.label.length>16?it.label.substring(0,16)+'..':it.label}</text>`;
    s+=`<rect x="${pad.l}" y="${y}" width="${bw}" height="${bH}" fill="${it.color||'#3498db'}" rx="3"/>`;
    s+=`<text x="${pad.l+bw+4}" y="${y+bH/2+3}" font-size="7" font-weight="700" fill="#2c3e50">${it.value.toLocaleString()}</text>`;
  });
  return `<svg width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">${s}</svg>`;
}

const palette = ['#2ecc71','#3498db','#9b59b6','#e67e22','#1abc9c','#e74c3c','#f39c12','#2980b9','#8e44ad','#16a085','#e91e63','#00bcd4','#8bc34a','#ff5722','#607d8b'];

// Build charts
const donutSvg = svgDonut(sevDef.map(s=>({value:sc[s.key],color:s.color})), 180, 180, 70, 45);
const donutLegend = sevDef.map(s=>`<div style="display:flex;align-items:center;margin:4px 0"><div style="width:14px;height:14px;border-radius:3px;background:${s.color};margin-right:8px"></div><div><div style="font-size:10px;font-weight:700">${s.key}</div><div style="font-size:8px;color:#95a5a6">${s.range}: ${sc[s.key].toLocaleString()}</div></div></div>`).join('');

const timelineSvg = svgVBars(d.timeline.map(t=>({value:t.count,label:t.hour,color:'#3498db'})), 500, 150);
const agentSvg = svgHBars(d.top_agents.map((a,i)=>({value:a.count,label:a.name,color:palette[i%15]})), 500, Math.max(d.top_agents.length*19+10,80));
const techSvg = svgHBars(d.mitre_techniques.map((m,i)=>({value:m.count,label:m.technique,color:palette[i%15]})), 500, Math.max(d.mitre_techniques.length*19+10,80));
const tacticSvg = svgHBars(d.mitre_tactics.map((m,i)=>({value:m.count,label:m.tactic,color:palette[i%15]})), 500, Math.max(d.mitre_tactics.length*19+10,80));

// Severity stat cards (matching Wazuh dashboard style)
const statCards = sevDef.map(s=>{
  const txtColor = s.key==='Critical'?'#BD271E':s.key==='High'?'#E7664C':s.key==='Medium'?'#D6BF57':'#6DCCB1';
  return `<div style="flex:1;text-align:center;padding:14px 6px;border-radius:8px;border:1px solid #ecf0f1;background:#fafbfc"><div style="font-size:10px;font-weight:600;color:#69707D;margin-bottom:6px">${s.key} severity</div><div style="font-size:26px;font-weight:800;color:${txtColor}">${sc[s.key].toLocaleString()}</div><div style="font-size:8px;color:#98A2B3;margin-top:3px">${s.range}</div></div>`;
}).join('');

// Alerts table sorted by level desc
const sortedRules = [...d.top_rules].sort((a,b)=>b.level-a.level||b.count-a.count);
const perPage = 40;
const makeRow = (r,i,offset) => {
  const sn = offset+i+1;
  const lc = r.level>=15?'#BD271E':r.level>=12?'#E7664C':r.level>=7?'#D6BF57':'#6DCCB1';
  const bg = i%2===0?'#fff':'#f8f9fb';
  return `<tr style="background:${bg};border-left:3px solid ${lc}"><td style="padding:3px 6px;border-bottom:1px solid #ecf0f1;text-align:center;font-weight:600;color:#95a5a6;font-size:7px">${sn}</td><td style="padding:3px 6px;border-bottom:1px solid #ecf0f1;text-align:center;font-weight:700;color:#2c3e50;font-size:8px">${r.rule_id}</td><td style="padding:3px 6px;border-bottom:1px solid #ecf0f1;font-size:7.5px;color:#34495e">${r.description.length>90?r.description.substring(0,90)+'...':r.description}</td><td style="padding:5px 8px;border-bottom:1px solid #ecf0f1;text-align:center"><span style="background:${lc};color:#fff;padding:2px 8px;border-radius:10px;font-size:7px;font-weight:700">${r.level}</span></td><td style="padding:3px 6px;border-bottom:1px solid #ecf0f1;text-align:right;font-weight:700;color:#2c3e50;font-size:8px">${r.count.toLocaleString()}</td></tr>`;
};
const ruleRowsPage1 = sortedRules.slice(0,perPage).map((r,i)=>makeRow(r,i,0)).join('');
const ruleRowsPage2 = sortedRules.slice(perPage,perPage*2).map((r,i)=>makeRow(r,i,perPage)).join('');

const logoImg = d.client_logo ? `<img src="${d.client_logo}" style="height:60px;display:block" onerror="this.style.display='none'"/>` : '';
// No logo in footer - only on cover page

const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Weekly Security Threat Analysis Report</title>
<style>
@page{size:A4 portrait;margin:0}
*{margin:0;padding:0;box-sizing:border-box}
body{font-family:'Segoe UI',Arial,sans-serif;font-size:9px;color:#2c3e50;background:#fff}
.page{page-break-after:always;width:210mm;min-height:297mm;padding:20px 24px 40px;position:relative}
.page:last-child{page-break-after:auto}
.card{background:#fff;border-radius:10px;box-shadow:0 1px 6px rgba(0,0,0,0.05);padding:14px;margin-bottom:12px;border:1px solid #ecf0f1}
.stitle{font-size:12px;font-weight:700;color:#2c3e50;margin:0 0 10px;padding:6px 0;border-bottom:2px solid #3498db;display:flex;align-items:center}
.stitle .dot{width:8px;height:8px;border-radius:50%;background:#3498db;margin-right:8px;flex-shrink:0}
.hdr{background:linear-gradient(135deg,#1a1a2e,#16213e,#0f3460);color:#fff;padding:12px 20px;border-radius:8px;margin-bottom:14px}
.hdr h2{font-size:15px;font-weight:700;margin-bottom:2px}
.hdr p{font-size:8px;opacity:0.8}
body{counter-reset:page}
.page{counter-increment:page}
.page-num::after{content:counter(page)}
.footer{position:fixed;bottom:8px;left:24px;right:24px;text-align:center;font-size:7px;color:#bdc3c7;border-top:1px solid #ecf0f1;padding-top:4px}
table{width:100%;border-collapse:collapse;font-size:8px}
tr{page-break-inside:avoid;break-inside:avoid}
td{word-wrap:break-word;overflow-wrap:break-word;max-width:300px}
thead{display:table-header-group}
tbody{display:table-row-group}
tr{page-break-inside:avoid;break-inside:avoid}
@media print{tr{page-break-inside:avoid}thead{display:table-header-group}}
thead th{background:linear-gradient(135deg,#1a1a2e,#16213e);color:#fff;padding:6px 8px;text-align:left;font-size:7.5px;text-transform:uppercase;letter-spacing:0.5px}
</style></head><body>

<!-- COVER PAGE -->
<div class=\"page\" style=\"padding:0;overflow:hidden;position:relative;background:#1B2A4A\">
  <!-- Large geometric accent -->
  <div style=\"position:absolute;top:-100px;right:-100px;width:450px;height:450px;border-radius:50%;background:linear-gradient(135deg,#0D7377,#14919B);opacity:0.15\"></div>
  <div style=\"position:absolute;bottom:-150px;left:-100px;width:400px;height:400px;border-radius:50%;background:linear-gradient(135deg,#14919B,#0D7377);opacity:0.1\"></div>
  <!-- Top accent -->
  <div style=\"height:5px;background:linear-gradient(90deg,#0D7377,#14919B,#32DBC6)\"></div>

  <div style=\"position:relative;z-index:1;padding:60px 50px 40px\">
    <!-- Logo -->
    ${logoImg ? '<div style=\"margin-bottom:40px;display:inline-flex;align-items:center;justify-content:center;background:#fff;padding:16px;border-radius:8px;box-shadow:0 2px 8px rgba(0,0,0,0.15)\">' + logoImg.replace('height:60px','height:40px') + '</div>' : ''}

    <!-- Title block -->
    <div style=\"margin-bottom:50px\">
      <div style=\"font-size:14px;color:#14919B;text-transform:uppercase;letter-spacing:4px;font-weight:600;margin-bottom:14px\">Security Report</div>
      <h1 style=\"font-size:48px;font-weight:800;color:#fff;line-height:1.05;margin-bottom:0\">Weekly Security Threat</h1>
      <h1 style=\"font-size:48px;font-weight:800;color:#14919B;line-height:1.05;margin-bottom:16px\">Analysis Report</h1>
      <div style=\"width:50px;height:4px;background:#14919B;border-radius:2px\"></div>
    </div>

    <!-- Subtitle -->
    <p style=\"font-size:13px;color:rgba(255,255,255,0.45);letter-spacing:1px;margin-bottom:40px\">Weekly Security Threat Analysis &bull; Last 7 Days</p>

    <!-- Info grid -->
    <div style=\"display:flex;gap:0;margin-bottom:40px;background:rgba(0,0,0,0.2);border-radius:8px;overflow:hidden\">
      <div style=\"flex:1;padding:18px 22px;border-left:3px solid #14919B\">
        <div style=\"font-size:8px;text-transform:uppercase;letter-spacing:2px;color:rgba(255,255,255,0.4);margin-bottom:8px\">Prepared For</div>
        <div style=\"font-size:15px;font-weight:700;color:#fff;margin-bottom:4px\">${d.client_name}</div>
        <div style=\"font-size:10px;color:rgba(255,255,255,0.5);line-height:1.4\">${d.client_address}</div>
      </div>
      <div style=\"flex:1;padding:18px 22px;border-left:1px solid rgba(255,255,255,0.08)\">
        <div style=\"font-size:8px;text-transform:uppercase;letter-spacing:2px;color:rgba(255,255,255,0.4);margin-bottom:8px\">Period</div>
        <div style=\"font-size:11px;font-weight:600;color:#fff;margin-bottom:4px\">${d.from_date}</div>
        <div style=\"font-size:11px;font-weight:600;color:#fff\">${d.to_date}</div>
      </div>
      <div style=\"flex:1;padding:18px 22px;border-left:1px solid rgba(255,255,255,0.08)\">
        <div style=\"font-size:8px;text-transform:uppercase;letter-spacing:2px;color:rgba(255,255,255,0.4);margin-bottom:8px\">Generated</div>
        <div style=\"font-size:11px;font-weight:600;color:#fff;margin-bottom:4px\">${d.ist_date}</div>
        <div style=\"font-size:11px;color:rgba(255,255,255,0.5)\">${d.ist_time} IST</div>
      </div>
    </div>
  </div>


</div>

<!-- PAGE 2: Table of Contents -->
<div class="page">
  <div class="hdr"><h2>Table of Contents</h2><p>Report sections overview</p></div>
  <div style="padding:10px 20px">
    <div style="border-bottom:1px dashed #ecf0f1;padding:10px 0;display:flex;justify-content:space-between;font-size:11px"><span style="font-weight:700;color:#1a1a2e">1. Executive Summary</span><span style="color:#95a5a6">Severity overview, week-over-week, timeline</span></div>
    <div style="border-bottom:1px dashed #ecf0f1;padding:10px 0;display:flex;justify-content:space-between;font-size:11px"><span style="font-weight:700;color:#1a1a2e">2. Top Threat Alerts</span><span style="color:#95a5a6">Critical & high severity events</span></div>
    <div style="border-bottom:1px dashed #ecf0f1;padding:10px 0;display:flex;justify-content:space-between;font-size:11px">${d.incident_count>0?'<span style="font-weight:700;color:#1a1a2e">3. Agents & Risk Assessment</span>':'<span style="font-weight:700;color:#1a1a2e">2. Agents & Risk Assessment</span>'}<span style="color:#95a5a6">Agent risk scores, actionable items</span></div>
    <div style="border-bottom:1px dashed #ecf0f1;padding:10px 0;display:flex;justify-content:space-between;font-size:11px">${d.incident_count>0?'<span style="font-weight:700;color:#1a1a2e">4. Authentication Events</span>':'<span style="font-weight:700;color:#1a1a2e">3. Authentication Events</span>'}<span style="color:#95a5a6">Login failures, successes, source IPs</span></div>
    <div style="border-bottom:1px dashed #ecf0f1;padding:10px 0;display:flex;justify-content:space-between;font-size:11px">${d.incident_count>0?'<span style="font-weight:700;color:#1a1a2e">5. Top Source IPs</span>':'<span style="font-weight:700;color:#1a1a2e">4. Top Source IPs</span>'}<span style="color:#95a5a6">Most active IP addresses</span></div>
    <div style="border-bottom:1px dashed #ecf0f1;padding:10px 0;display:flex;justify-content:space-between;font-size:11px">${d.incident_count>0?'<span style="font-weight:700;color:#1a1a2e">6. Vulnerability Detection</span>':'<span style="font-weight:700;color:#1a1a2e">5. Vulnerability Detection</span>'}<span style="color:#95a5a6">CVEs, affected agents, packages</span></div>
    <div style="border-bottom:1px dashed #ecf0f1;padding:10px 0;display:flex;justify-content:space-between;font-size:11px">${d.incident_count>0?'<span style="font-weight:700;color:#1a1a2e">7. File Integrity Monitoring</span>':'<span style="font-weight:700;color:#1a1a2e">6. File Integrity Monitoring</span>'}<span style="color:#95a5a6">File changes, modified paths</span></div>
    <div style="border-bottom:1px dashed #ecf0f1;padding:10px 0;display:flex;justify-content:space-between;font-size:11px">${d.incident_count>0?'<span style="font-weight:700;color:#1a1a2e">8. MITRE ATT&amp;CK Analysis</span>':'<span style="font-weight:700;color:#1a1a2e">7. MITRE ATT&amp;CK Analysis</span>'}<span style="color:#95a5a6">Techniques, tactics mapping</span></div>
    <div style="border-bottom:1px dashed #ecf0f1;padding:10px 0;display:flex;justify-content:space-between;font-size:11px">${d.incident_count>0?'<span style="font-weight:700;color:#1a1a2e">9. Regulatory Compliance</span>':'<span style="font-weight:700;color:#1a1a2e">8. Regulatory Compliance</span>'}<span style="color:#95a5a6">PCI-DSS, HIPAA, GDPR, NIST 800-53</span></div>
    <div style="border-bottom:1px dashed #ecf0f1;padding:10px 0;display:flex;justify-content:space-between;font-size:11px">${d.incident_count>0?'<span style="font-weight:700;color:#1a1a2e">10. Security Events Summary</span>':'<span style="font-weight:700;color:#1a1a2e">9. Security Events Summary</span>'}<span style="color:#95a5a6">All rules sorted by severity</span></div>
  </div>
</div>
<!-- PAGE 3: Executive Summary -->
<div class="page">
  <div class="hdr"><h2>Executive Summary</h2><p>Last 7 days alert overview</p></div>
  <div class="card" style="background:#f8f9fb;border-left:4px solid #3498db;margin-bottom:14px">
    <div style="font-size:9px;line-height:1.6;color:#34495e">
      During the reporting period <strong>${d.from_date}</strong> to <strong>${d.to_date}</strong>, a total of <strong>${d.total_alerts.toLocaleString()}</strong> security alerts were recorded across all monitored endpoints. Of these, <strong style="color:#BD271E">${sc.Critical.toLocaleString()} critical</strong> and <strong style="color:#E7664C">${sc.High.toLocaleString()} high</strong> severity alerts (level 12+: ${d.level12_count.toLocaleString()}) require immediate attention. There were <strong style="color:#e74c3c">${d.auth_fail_count.toLocaleString()} authentication failures</strong> and <strong style="color:#2ecc71">${d.auth_success_count.toLocaleString()} successful logons</strong> detected. ${d.vuln_total > 0 ? 'Vulnerability detection identified <strong>' + d.vuln_total.toLocaleString() + ' vulnerability events</strong> across monitored agents.' : 'No vulnerability events were detected in this period.'} The top generating agent was <strong>${d.top_agents[0]?.name || 'N/A'}</strong> with ${d.top_agents[0]?.count.toLocaleString() || '0'} alerts. MITRE ATT&amp;CK mapping shows <strong>${d.mitre_techniques.length} techniques</strong> across <strong>${d.mitre_tactics.length} tactics</strong>.
    </div>
  </div>
  <div class="card" style="margin-bottom:14px;padding:10px 16px">
    <div class="stitle" style="margin-bottom:8px"><span class="dot" style="background:#9b59b6"></span>Week-over-Week Comparison <span style="font-size:8px;font-weight:400;color:#95a5a6;margin-left:6px">(Previous Week vs Current Week)</span></div>
    <div style="display:flex;gap:10px;font-size:9px">${['Critical','High','Medium','Low'].map(k=>{ const today=sc[k]; const prev=d.prev_week_severity[k]; const diff=today-prev; const pct=prev>0?((diff/prev)*100).toFixed(1):'N/A'; const arrow=diff>0?'\u25B2':diff<0?'\u25BC':'\u25CF'; const color=diff>0?'#e74c3c':diff<0?'#2ecc71':'#95a5a6'; return '<div style="flex:1;text-align:center;padding:8px;border-radius:6px;background:#fafbfc;border:1px solid #ecf0f1"><div style="font-size:8px;color:#69707D;margin-bottom:3px">'+k+'</div><div style="font-size:12px;font-weight:700;color:'+color+'">'+arrow+' '+(pct==='N/A'?'N/A':pct+'%')+'</div><div style="font-size:7px;color:#95a5a6;margin-top:2px">'+prev.toLocaleString()+' &rarr; '+today.toLocaleString()+'</div></div>'; }).join('')}<div style="flex:1;text-align:center;padding:8px;border-radius:6px;background:#fafbfc;border:1px solid #ecf0f1"><div style="font-size:8px;color:#69707D;margin-bottom:3px">Total</div><div style="font-size:12px;font-weight:700;color:${d.total_alerts>d.prev_week_total?'#e74c3c':d.total_alerts<d.prev_week_total?'#2ecc71':'#95a5a6'}">${d.total_alerts>d.prev_week_total?'\u25B2':d.total_alerts<d.prev_week_total?'\u25BC':'\u25CF'} ${d.prev_week_total>0?((d.total_alerts-d.prev_week_total)/d.prev_week_total*100).toFixed(1):'N/A'}%</div><div style="font-size:7px;color:#95a5a6;margin-top:2px">${d.prev_week_total.toLocaleString()} &rarr; ${d.total_alerts.toLocaleString()}</div></div></div>
  </div>
  <div style="display:flex;gap:8px;margin-bottom:14px">${statCards}</div>
  <div class="card">
    <div class="stitle"><span class="dot"></span>Severity Distribution</div>
    <div style="display:flex;align-items:center;justify-content:center;gap:24px">
      ${donutSvg}
      <div>${donutLegend}</div>
    </div>
  </div>
  <div class="card">
    <div class="stitle"><span class="dot"></span>Alerts Timeline (7 Days)</div>
    <div style="text-align:center">${timelineSvg}</div>
  </div>


  <div class="card">
    <div class="stitle"><span class="dot" style="background:#3498db"></span>Daily Alert Trend (7 Days)</div>
    <div style="text-align:center">
      ${(()=>{
        const data=d.daily_trend||[];
        if(!data.length) return '<div style="color:#95a5a6;font-size:9px;padding:20px">No trend data</div>';
        const max=Math.max(...data.map(x=>x.total),1);
        const w=480,h=160,barW=Math.floor((w-40)/data.length)-4,pad=20;
        let svg='<svg width="'+w+'" height="'+(h+30)+'" style="font-family:Inter,sans-serif">';
        // Grid lines
        for(let i=0;i<=4;i++){const y=pad+((h-pad*2)*i/4);svg+='<line x1="35" y1="'+y+'" x2="'+(w-5)+'" y2="'+y+'" stroke="#ecf0f1" stroke-width="0.5"/><text x="30" y="'+(y+3)+'" text-anchor="end" font-size="7" fill="#95a5a6">'+Math.round(max*(1-i/4))+'</text>';}
        // Bars (stacked: critical, high, medium, low)
        data.forEach((d2,i)=>{
          const x=40+i*(barW+4);
          const totalH=Math.round((d2.total/max)*(h-pad*2));
          const critH=Math.round((d2.critical/max)*(h-pad*2));
          const highH=Math.round((d2.high/max)*(h-pad*2));
          const medH=Math.round((d2.medium/max)*(h-pad*2));
          const lowH=totalH-critH-highH-medH;
          let y=h-pad;
          if(lowH>0){svg+='<rect x="'+x+'" y="'+(y-lowH)+'" width="'+barW+'" height="'+lowH+'" fill="#3498db" rx="1"/>';y-=lowH;}
          if(medH>0){svg+='<rect x="'+x+'" y="'+(y-medH)+'" width="'+barW+'" height="'+medH+'" fill="#f39c12" rx="1"/>';y-=medH;}
          if(highH>0){svg+='<rect x="'+x+'" y="'+(y-highH)+'" width="'+barW+'" height="'+highH+'" fill="#E7664C" rx="1"/>';y-=highH;}
          if(critH>0){svg+='<rect x="'+x+'" y="'+(y-critH)+'" width="'+barW+'" height="'+critH+'" fill="#BD271E" rx="1"/>';}
          // Day label
          svg+='<text x="'+(x+barW/2)+'" y="'+(h-pad+12)+'" text-anchor="middle" font-size="7" fill="#69707D">'+d2.day+'</text>';
          // Total on top
          svg+='<text x="'+(x+barW/2)+'" y="'+(h-pad-totalH-3)+'" text-anchor="middle" font-size="6" fill="#69707D" font-weight="600">'+d2.total+'</text>';
        });
        // Legend
        svg+='<rect x="40" y="'+(h+14)+'" width="8" height="8" fill="#BD271E" rx="1"/><text x="52" y="'+(h+21)+'" font-size="7" fill="#69707D">Critical</text>';
        svg+='<rect x="100" y="'+(h+14)+'" width="8" height="8" fill="#E7664C" rx="1"/><text x="112" y="'+(h+21)+'" font-size="7" fill="#69707D">High</text>';
        svg+='<rect x="145" y="'+(h+14)+'" width="8" height="8" fill="#f39c12" rx="1"/><text x="157" y="'+(h+21)+'" font-size="7" fill="#69707D">Medium</text>';
        svg+='<rect x="200" y="'+(h+14)+'" width="8" height="8" fill="#3498db" rx="1"/><text x="212" y="'+(h+21)+'" font-size="7" fill="#69707D">Low</text>';
        svg+='</svg>';
        return svg;
      })()}
    </div>
    <div style="text-align:center;font-size:8px;color:#69707D;margin-top:4px">Peak Day: <strong>${d.peak_day}</strong></div>
  </div>
</div>



<!-- PAGE: Top Threat Alerts -->
<div class="page">
  <div class="hdr" style="background:linear-gradient(135deg,#BD271E,#920000)"><h2 style="color:#fff">Top Threat Alerts</h2><p style="color:rgba(255,255,255,0.8)">${d.incident_count>0?d.incident_count+' critical/high severity events in last 7 days':'No high severity threats detected in last 7 days'}</p></div>
  ${d.incident_count>0?'<div style="background:#fdf2f2;border:2px solid #BD271E;border-radius:8px;padding:14px;margin-bottom:14px"><div style="display:flex;align-items:center;gap:8px;margin-bottom:8px"><div style="width:28px;height:28px;background:#BD271E;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:14px;color:#fff;font-weight:800">!</div><div style="font-size:12px;font-weight:700;color:#BD271E">HIGH SEVERITY THREATS DETECTED</div></div><div style="font-size:9px;color:#69707D">The following events have severity level 12 or above and may indicate active threats, successful attacks, or critical system changes.</div></div><table><thead><tr><th style="width:35px">Level</th><th>Description</th><th style="width:50px;text-align:center">Count</th><th style="width:120px">Affected Agents</th><th style="width:100px">Last Seen (IST)</th></tr></thead><tbody>'+d.incidents.map((inc,i)=>'<tr style="background:'+(i%2===0?'#fff':'#f8f9fb')+'"><td style="padding:5px 8px;border-bottom:1px solid #ecf0f1;text-align:center"><span style="background:'+(inc.level>=15?'#BD271E':'#E7664C')+';color:#fff;padding:2px 6px;border-radius:4px;font-size:8px;font-weight:700">'+inc.level+'</span></td><td style="padding:5px 8px;border-bottom:1px solid #ecf0f1;font-size:8px">'+inc.description+'</td><td style="padding:5px 8px;border-bottom:1px solid #ecf0f1;text-align:center;font-size:9px;font-weight:700;color:#BD271E">'+inc.count.toLocaleString()+'</td><td style="padding:5px 8px;border-bottom:1px solid #ecf0f1;font-size:8px">'+inc.agents+'</td><td style="padding:5px 8px;border-bottom:1px solid #ecf0f1;font-size:7px">'+inc.last_seen+'</td></tr>').join('')+'</tbody></table>':'<div style="text-align:center;padding:60px 20px"><div style="width:64px;height:64px;background:#f0fdf4;border-radius:50%;display:inline-flex;align-items:center;justify-content:center;margin-bottom:16px"><svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="#2ecc71" stroke-width="2"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg></div><div style="font-size:16px;font-weight:700;color:#1a1a2e;margin-bottom:6px">No Top Threats Found</div><div style="font-size:10px;color:#69707D;max-width:400px;margin:0 auto">No alerts with severity level 12 or above were detected during the reporting period. This indicates no critical or high-severity security events occurred.</div></div>'}
</div>


<!-- PAGE: Agents &amp; Risk Assessment -->
<div class=\"page\">
  <div class=\"hdr\"><h2>Agents &amp; Risk Assessment</h2><p>Agent overview, severity breakdown, risk scoring and recommendations</p></div>
  <div class=\"card\">
    <div class=\"stitle\"><span class=\"dot\" style=\"background:#2ecc71\"></span>Top ${d.top_agents.length} Agents (Alert Volume)</div>
    <div style=\"text-align:center\">${agentSvg}</div>
  </div>
  <div class=\"card\"><div class=\"stitle\"><span class=\"dot\" style=\"background:#e74c3c\"></span>Agent Risk Scores</div>
    <table><thead><tr><th>Agent</th><th style=\"text-align:center\">Total</th><th style=\"text-align:center;color:#BD271E\">Crit</th><th style=\"text-align:center;color:#E7664C\">High</th><th style=\"text-align:center;color:#D6BF57\">Med</th><th style=\"text-align:center\">Score</th><th style=\"text-align:center\">Risk</th><th>Action</th></tr></thead><tbody>${d.agent_risk.map((a,i)=>{ const rc=a.risk==='Critical'?'#BD271E':a.risk==='High'?'#E7664C':a.risk==='Medium'?'#D6BF57':'#6DCCB1'; return '<tr style=\"background:'+(i%2===0?'#fff':'#f8f9fb')+';border-left:3px solid '+rc+'\">'+ '<td style=\"padding:4px 6px;border-bottom:1px solid #ecf0f1;font-size:8px;font-weight:600\">'+a.name+'</td>'+'<td style=\"padding:4px 6px;border-bottom:1px solid #ecf0f1;text-align:center;font-size:8px\">'+a.count.toLocaleString()+'</td>'+'<td style=\"padding:4px 6px;border-bottom:1px solid #ecf0f1;text-align:center;font-size:8px;font-weight:700;color:#BD271E\">'+(a.critical||'-')+'</td>'+'<td style=\"padding:4px 6px;border-bottom:1px solid #ecf0f1;text-align:center;font-size:8px;font-weight:700;color:#E7664C\">'+(a.high||'-')+'</td>'+'<td style=\"padding:4px 6px;border-bottom:1px solid #ecf0f1;text-align:center;font-size:8px;color:#D6BF57\">'+(a.medium>0?a.medium.toLocaleString():'-')+'</td>'+'<td style=\"padding:4px 6px;border-bottom:1px solid #ecf0f1;text-align:center\"><div style=\"background:#ecf0f1;border-radius:8px;height:12px;overflow:hidden;width:50px;display:inline-block\"><div style=\"background:'+rc+';height:100%;width:'+a.score+'%;border-radius:8px\"></div></div><span style=\"font-size:7px;font-weight:700;color:'+rc+';margin-left:3px\">'+a.score+'</span></td>'+'<td style=\"padding:4px 6px;border-bottom:1px solid #ecf0f1;text-align:center\"><span style=\"background:'+rc+';color:#fff;padding:1px 6px;border-radius:8px;font-size:6.5px;font-weight:700\">'+a.risk+'</span></td>'+'<td style=\"padding:4px 6px;border-bottom:1px solid #ecf0f1;font-size:7px;color:#69707D;font-style:italic\">'+a.note+'</td></tr>'; }).join('')}</tbody></table>
