    <div class="card" style="flex:1"><div class="stitle"><span class="dot" style="background:#9b59b6"></span>NIST 800-53 Controls</div>${d.compliance_nist_controls.length>0?'<table><thead><tr><th>Control</th><th style="text-align:right">Alerts</th></tr></thead><tbody>'+d.compliance_nist_controls.map((c,i)=>'<tr style="background:'+(i%2===0?'#fff':'#f8f9fb')+'"><td style="padding:3px 8px;border-bottom:1px solid #ecf0f1;font-size:8px;font-family:monospace">'+c.control+'</td><td style="padding:3px 8px;border-bottom:1px solid #ecf0f1;text-align:right;font-weight:700;font-size:8px">'+c.count.toLocaleString()+'</td></tr>').join('')+'</tbody></table>':'<div style="text-align:center;color:#95a5a6;font-size:9px;padding:12px">No NIST data</div>'}</div>
  ${d.compliance_tsc_controls.length>0?'<div class="card"><div class="stitle"><span class="dot" style="background:#8e44ad"></span>TSC (Trust Services Criteria)</div><table><thead><tr><th>Criteria</th><th style="text-align:right">Alerts</th></tr></thead><tbody>'+d.compliance_tsc_controls.map((c,i)=>'<tr style="background:'+(i%2===0?'#fff':'#f8f9fb')+'"><td style="padding:3px 8px;border-bottom:1px solid #ecf0f1;font-size:8px;font-family:monospace">'+c.control+'</td><td style="padding:3px 8px;border-bottom:1px solid #ecf0f1;text-align:right;font-weight:700;font-size:8px">'+c.count.toLocaleString()+'</td></tr>').join('')+'</tbody></table></div>':''}
</div>
